// Generates the Python HMAC demo shown on the Done step.
//
// Mirrors what the lesson did in JS: compute HMAC-SHA256 with the user's
// key + message, verify, then verify a tampered version (which fails).
// Uses stdlib only — `hmac` + `hashlib`. No third-party dependencies.

export function full_script(state) {
  const key = (state && state.hm_key) || "shared-secret";
  const message =
    (state && state.hm_message) || "transfer=100&to=alice";
  const keyLit = JSON.stringify(key);
  const msgLit = JSON.stringify(message);
  return [
    "# HMAC in Python — generated by cloak.moosha.org",
    "#",
    "# This is the production equivalent of what the lesson did in your",
    "# browser. Python's stdlib `hmac` module implements RFC 2104; we pair",
    "# it with `hashlib.sha256` to get HMAC-SHA256, the same algorithm Web",
    "# Crypto's subtle.sign({name: 'HMAC', hash: 'SHA-256'}) uses.",
    "#",
    "# Use hmac.compare_digest (NOT ==) when comparing MACs — it's",
    "# constant-time and so doesn't leak timing information about how many",
    "# leading bytes matched.",
    "",
    "import hmac",
    "import hashlib",
    "",
    `KEY = ${keyLit}.encode("utf-8")`,
    `MESSAGE = ${msgLit}.encode("utf-8")`,
    "",
    "# --- Sender side --------------------------------------------------",
    "mac = hmac.new(KEY, MESSAGE, hashlib.sha256).hexdigest()",
    'print("MAC:", mac)',
    "",
    "# --- Receiver side, honest case ----------------------------------",
    "# Receiver recomputes HMAC over the message they received and",
    "# compares against the MAC the sender supplied.",
    "expected = hmac.new(KEY, MESSAGE, hashlib.sha256).hexdigest()",
    "assert hmac.compare_digest(mac, expected)",
    'print("\\u2713 verify OK")',
    "",
    "# --- Receiver side, tampered case --------------------------------",
    "# Flip one byte of the message and recompute. The MAC won't match —",
    "# the receiver knows the message was altered (or not sent by",
    "# someone with the key).",
    "tampered = MESSAGE[:-1] + bytes([MESSAGE[-1] ^ 1])",
    "tampered_mac = hmac.new(KEY, tampered, hashlib.sha256).hexdigest()",
    "assert not hmac.compare_digest(mac, tampered_mac)",
    'print("\\u2713 tamper rejected:", tampered)',
    "",
    "# That's HMAC: cheap to compute, impossible to forge without the",
    "# key, immune to length-extension because of the nested-hash",
    "# construction H((K\\u2032 XOR opad) || H((K\\u2032 XOR ipad) || m)).",
  ].join("\n");
}

